class TrimCurve(NodeBuilder):
    """
    Shorten curves by removing portions at the start or end

    Parameters
    ----------
    curve : InputGeometry
        Curve
    selection : InputBoolean
        Selection
    start : InputFloat
        Start
    end : InputFloat
        End
    start_001 : InputFloat
        Start
    end_001 : InputFloat
        End

    Outputs
    -------
    curve : GeometrySocket
        Curve
    """

    _bl_idname = "GeometryNodeTrimCurve"
    node: bpy.types.GeometryNodeTrimCurve

    class _Inputs(SocketAccessor):
        curve: GeometrySocket
        selection: BooleanSocket
        start: FloatSocket
        end: FloatSocket
        start_001: FloatSocket
        end_001: FloatSocket

    class _Outputs(SocketAccessor):
        curve: GeometrySocket

    if TYPE_CHECKING:

        @property
        def i(self) -> _Inputs: ...
        @property
        def o(self) -> _Outputs: ...

    def __init__(
        self,
        curve: InputGeometry = None,
        selection: InputBoolean = True,
        start: InputFloat = 0.0,
        end: InputFloat = 1.0,
        start_001: InputFloat = 0.0,
        end_001: InputFloat = 1.0,
        *,
        mode: Literal["FACTOR", "LENGTH"] = "FACTOR",
    ):
        super().__init__()
        key_args = {
            "Curve": curve,
            "Selection": selection,
            "Start": start,
            "End": end,
            "Start_001": start_001,
            "End_001": end_001,
        }
        self.mode = mode
        self._establish_links(**key_args)

    @classmethod
    def factor(
        cls,
        curve: InputGeometry = None,
        selection: InputBoolean = True,
        start: InputFloat = 0.0,
        end: InputFloat = 1.0,
    ) -> "TrimCurve":
        """Create Trim Curve with operation 'Factor'. Find the endpoint positions using a factor of each spline's length"""
        return cls(
            mode="FACTOR", curve=curve, selection=selection, start=start, end=end
        )

    @classmethod
    def length(
        cls,
        curve: InputGeometry = None,
        selection: InputBoolean = True,
        start_001: InputFloat = 0.0,
        end_001: InputFloat = 1.0,
    ) -> "TrimCurve":
        """Create Trim Curve with operation 'Length'. Find the endpoint positions using a length from the start of each spline"""
        return cls(
            mode="LENGTH",
            curve=curve,
            selection=selection,
            start_001=start_001,
            end_001=end_001,
        )

    @property
    def mode(self) -> Literal["FACTOR", "LENGTH"]:
        return self.node.mode

    @mode.setter
    def mode(self, value: Literal["FACTOR", "LENGTH"]):
        self.node.mode = value


